import { get, isNil } from 'lodash-es';

import { ColorRuleProps } from '../../../types/color-rule.js';
import { getColorPalette } from '../../../utils/get-color-palette.js';
import { getAccessor } from '../../../utils/getAccessor.js';
import { getValidColor } from '../../../utils/getValidColor.js';
import { buildValidator, VALUE_MATCHERS } from '../../../utils/validators.js';

const getSubject = (
  rule: ColorRuleProps,
  rawData: Record<string, unknown> | undefined,
) => {
  const valueAccessor = rule.valueAccessor;
  if (!valueAccessor || !rawData) {
    return null;
  }

  const accessor = getAccessor(valueAccessor);

  if (accessor) {
    const value = get(rawData, accessor);
    if (!isNil(value)) {
      return value;
    }
  }
  return null;
};

export const applyColorRuleToSingleValue = (
  colorRules: ColorRuleProps[],
  value: number | string,
  dataItem?: Record<string, unknown>,
) => {
  const isValid = buildValidator(VALUE_MATCHERS);

  for (let i = colorRules.length - 1; i >= 0; i--) {
    const rule = colorRules[i];
    const subject = getSubject(rule, dataItem) ?? value;

    if (!isNil(subject) && isValid(subject, rule.comparator, rule.matchValue)) {
      return rule.colorPalette
        ? getColorPalette(`${subject}`, 0, rule.colorPalette).Default
        : getValidColor(rule.color ?? '');
    }
  }
};
